import anthropic
import subprocess
import json
from pathlib import Path
from dataclasses import dataclass, field
from typing import Any

@dataclass
class PipelineStage:
    name: str
    description: str
    command: str
    input_files: list[str]
    output_files: list[str]
    status: str = "pending"  # pending, running, done, failed
    result: dict = field(default_factory=dict)

@dataclass
class DiscoveryPipeline:
    name: str
    objective: str
    stages: list[PipelineStage]
    work_dir: Path

class LLMOrchestrator:
    def __init__(self):
        self.client = anthropic.Anthropic()

    def plan_pipeline(self, objective: str, available_tools: list[str]) -> list[dict]:
        """Ask LLM to plan pipeline stages for a scientific objective."""
        response = self.client.messages.create(
            model="claude-opus-4-5",
            max_tokens=1024,
            messages=[{"role": "user", "content": f"""
Plan a scientific discovery pipeline for this objective.
Return JSON list of stages:
[{{"name": "...", "description": "...", "command": "python scripts/<stage>.py --input {{input}} --output {{output}}"}}]

Objective: {objective}
Available tools: {", ".join(available_tools)}
"""}]
        )
        text = response.content[0].text
        start, end = text.find("["), text.rfind("]") + 1
        return json.loads(text[start:end]) if start >= 0 else []

    def interpret_results(self, stage_name: str, results: dict, objective: str) -> dict:
        """Interpret stage results and decide next action."""
        response = self.client.messages.create(
            model="claude-opus-4-5",
            max_tokens=512,
            messages=[{"role": "user", "content": f"""
Interpret results from pipeline stage: {stage_name}
Research objective: {objective}
Results: {json.dumps(results)[:1000]}

Return JSON: {{"status": "proceed|revise|fail", "message": "...", "parameter_changes": {{}}}}
"""}]
        )
        text = response.content[0].text
        return json.loads(text[text.find("{"):text.rfind("}")+1])

def run_stage(stage: PipelineStage, work_dir: Path) -> dict:
    """Execute a pipeline stage and return results."""
    cmd = stage.command.format(
        input=work_dir / stage.input_files[0] if stage.input_files else "",
        output=work_dir / stage.output_files[0] if stage.output_files else "",
    )
    try:
        result = subprocess.run(
            cmd, shell=True, capture_output=True, text=True, timeout=300, cwd=work_dir
        )
        return {
            "returncode": result.returncode,
            "stdout": result.stdout[:2000],
            "stderr": result.stderr[:500],
        }
    except subprocess.TimeoutExpired:
        return {"returncode": -1, "stdout": "", "stderr": "Timeout"}

def run_discovery_pipeline(pipeline: DiscoveryPipeline) -> list[dict]:
    """Run all stages with LLM interpretation."""
    orchestrator = LLMOrchestrator()
    reports = []

    for stage in pipeline.stages:
        print(f"Running stage: {stage.name}")
        stage.status = "running"

        result = run_stage(stage, pipeline.work_dir)
        stage.result = result

        decision = orchestrator.interpret_results(stage.name, result, pipeline.objective)
        print(f"  Decision: {decision.get('status')} — {decision.get('message', '')[:80]}")

        if decision["status"] == "fail":
            stage.status = "failed"
            break
        elif decision["status"] == "revise":
            # Apply parameter changes and re-run (simplified)
            print(f"  Revising with: {decision.get('parameter_changes', {})}")
            result = run_stage(stage, pipeline.work_dir)

        stage.status = "done"
        reports.append({"stage": stage.name, "result": result, "decision": decision})

    return reports

# Example usage
orchestrator = LLMOrchestrator()
stages_plan = orchestrator.plan_pipeline(
    "Identify differentially expressed genes between treatment and control groups in RNA-seq data",
    ["deseq2", "enrichment_analysis", "pathway_mapping", "visualization"]
)
print(f"Planned {len(stages_plan)} stages")
